import { BASEPATH, PASSWORD, USERNAME } from '../config';
import { PaymentService } from './payment.wrapper';
describe('payment', () => {
    let service;
    beforeAll(async () => {
        service = new PaymentService({
            username: USERNAME,
            password: PASSWORD,
            basePath: BASEPATH,
        }, true);
    });
    it('getPaymentHistories', async () => {
        const response = await service.getPaymentHistories({
            page: 1,
            limit: 10,
            startDate: new Date('2024-01-01'),
            endDate: new Date('2024-02-29'),
        });
        expect(response).toBeDefined();
    });
    it('getPaymentHistoryDetail', async () => {
        const response = await service.getPaymentHistoryDetail(1);
        expect(response).toBeDefined();
    });
});
